// Ambient declarations for the Web Speech API. Browsers ship the runtime
// implementation as `SpeechRecognition` or `webkitSpeechRecognition`, but
// `lib.dom.d.ts` only types the supporting `SpeechRecognitionEvent` shapes,
// not the constructor itself. These declarations cover the surface used by
// `useIdeaFlow`.

interface SpeechRecognition extends EventTarget {
  continuous: boolean;
  interimResults: boolean;
  lang: string;
  onresult: ((this: SpeechRecognition, ev: SpeechRecognitionEvent) => void) | null;
  onend: ((this: SpeechRecognition, ev: Event) => void) | null;
  onerror: ((this: SpeechRecognition, ev: Event) => void) | null;
  start(): void;
  stop(): void;
  abort(): void;
}

declare const SpeechRecognition: {
  prototype: SpeechRecognition;
  new (): SpeechRecognition;
};

interface Window {
  SpeechRecognition?: typeof SpeechRecognition;
  webkitSpeechRecognition?: typeof SpeechRecognition;
}
